+  remote: string
+  ...rest
+] {
+  $repository
+    | str replace -r r#'^.*\/(.*)\.git$'# './$1'
+    | path join (git-remote-default-branch $repository)
+    | do -c --env {
+      ^git clone $repository $in ...$rest
