+def git-current-branch [] {
+  error-is-not-git-repo
+  ^git rev-parse --abbrev-ref HEAD | complete | get stdout | str trim
+}
+
+def git-branch-root [] {
+  error-is-not-git-repo
+  ^git rev-parse --show-toplevel | complete | get stdout | str trim
+}

